@namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply

<section class="step-content">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" value="@Model.FullName"
               @onchange="e => UpdateModel(Model with { FullName = (string?)e.Value ?? string.Empty })" />
    </div>

    <div class="form-group">
        <label>Email *</label>
        <input type="email" value="@Model.Email"
               @onchange="e => UpdateModel(Model with { Email = (string?)e.Value ?? string.Empty })" />
        @if (!string.IsNullOrEmpty(EmailError))
        {
            <span class="error">@EmailError</span>
        }
    </div>

    <div class="form-group">
        <label>Phone *</label>
        <input type="tel" value="@Model.Phone"
               @onchange="e => UpdateModel(Model with { Phone = (string?)e.Value ?? string.Empty })" />
    </div>

    <div class="form-group">
        <label>Address *</label>
        <textarea rows="2" value="@Model.Address"
                  @onchange="e => UpdateModel(Model with { Address = (string?)e.Value ?? string.Empty })"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="error">@ValidationError</div>
    }

    <div class="step-actions">
        <button type="button" class="btn-next" @onclick="HandleNext" disabled="@IsValidating">
            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<PersonalInfoModel> OnModelChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ValidationError;
    private string? EmailError;
    private bool IsValidating;

    private async Task UpdateModel(PersonalInfoModel updated)
    {
        EmailError = null;
        await OnModelChanged.InvokeAsync(updated);
    }

    private async Task HandleNext()
    {
        ValidationError = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ValidationError = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Model.Email);
            if (!emailValid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply

<section class="step-content">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="index"
                       CanRemove="@(Entries.Count > 1)"
                       OnChanged="e => HandleEntryChanged(index, e)"
                       OnRemove="() => HandleRemoveEntry(index)" />
    }

    <button type="button" class="btn-add" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="error">@ValidationError</div>
    }

    <div class="step-actions">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> OnEntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private async Task HandleEntryChanged(int index, WorkEntryModel updated)
    {
        var list = new List<WorkEntryModel>(Entries);
        list[index] = updated;
        await OnEntriesChanged.InvokeAsync(list);
    }

    private async Task HandleRemoveEntry(int index)
    {
        var list = new List<WorkEntryModel>(Entries);
        list.RemoveAt(index);
        await OnEntriesChanged.InvokeAsync(list);
    }

    private async Task AddEntry()
    {
        var list = new List<WorkEntryModel>(Entries)
        {
            new(string.Empty, string.Empty, DateTime.Today, null, string.Empty)
        };
        await OnEntriesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        ValidationError = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ValidationError = "Each position requires at least a company name and job title.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply

<section class="step-content">
    <h2>References</h2>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="@References[index]"
                       Index="index"
                       CanRemove="@(References.Count > 2)"
                       OnChanged="e => HandleReferenceChanged(index, e)"
                       OnRemove="() => HandleRemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-add" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="error">@ValidationError</div>
    }

    <div class="step-actions">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<ReferenceModel>> OnReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private async Task HandleReferenceChanged(int index, ReferenceModel updated)
    {
        var list = new List<ReferenceModel>(References);
        list[index] = updated;
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task HandleRemoveReference(int index)
    {
        var list = new List<ReferenceModel>(References);
        list.RemoveAt(index);
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<ReferenceModel>(References)
        {
            new(string.Empty, string.Empty, string.Empty, string.Empty)
        };
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        ValidationError = null;
        if (References.Count < 2)
        {
            ValidationError = "Please provide at least 2 references.";
            return;
        }
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                ValidationError = "Each reference requires at least a name and email.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply

<section class="step-content">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <textarea rows="12" maxlength="@MaxLength" value="@CoverLetter"
                  @oninput="HandleInput"></textarea>
        <div class="char-count">@CoverLetter.Length / @MaxLength characters</div>
    </div>

    <div class="step-actions">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public string CoverLetter { get; set; } = string.Empty;
    [Parameter, EditorRequired] public EventCallback<string> OnCoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var text = (string?)e.Value ?? string.Empty;
        if (text.Length > MaxLength)
            text = text[..MaxLength];
        await OnCoverLetterChanged.InvokeAsync(text);
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync();
    }
}

@namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply

<section class="step-content review-step">
    <h2>Review & Submit</h2>

    <div class="review-section">
        <h3>Personal Information <a class="edit-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</a></h3>
        <dl>
            <dt>Name</dt><dd>@Personal.FullName</dd>
            <dt>Email</dt><dd>@Personal.Email</dd>
            <dt>Phone</dt><dd>@Personal.Phone</dd>
            <dt>Address</dt><dd>@Personal.Address</dd>
        </dl>
    </div>

    <div class="review-section">
        <h3>Work History <a class="edit-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</a></h3>
        @foreach (var entry in WorkEntries)
        {
            <div class="review-entry">
                <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                <span>@entry.StartDate.ToString("MMM yyyy") &ndash; @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")</span>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p>@entry.Description</p>
                }
            </div>
        }
    </div>

    <div class="review-section">
        <h3>References <a class="edit-link" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</a></h3>
        @foreach (var r in References)
        {
            <div class="review-entry">
                <strong>@r.Name</strong> (@r.Relationship)<br />
                @r.Email | @r.Phone
            </div>
        }
    </div>

    <div class="review-section">
        <h3>Cover Letter <a class="edit-link" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</a></h3>
        <p class="cover-letter-preview">@CoverLetter</p>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @(IsSubmitting ? "Submitting..." : "Submit Application")
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = string.Empty;
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }

    private bool IsSubmitting;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

