@namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply

<section class="step-content">
    <h2>References</h2>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="@References[index]"
                       Index="index"
                       CanRemove="@(References.Count > 2)"
                       OnChanged="e => HandleReferenceChanged(index, e)"
                       OnRemove="() => HandleRemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-add" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="error">@ValidationError</div>
    }

    <div class="step-actions">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<ReferenceModel>> OnReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private async Task HandleReferenceChanged(int index, ReferenceModel updated)
    {
        var list = new List<ReferenceModel>(References);
        list[index] = updated;
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task HandleRemoveReference(int index)
    {
        var list = new List<ReferenceModel>(References);
        list.RemoveAt(index);
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<ReferenceModel>(References)
        {
            new(string.Empty, string.Empty, string.Empty, string.Empty)
        };
        await OnReferencesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        ValidationError = null;
        if (References.Count < 2)
        {
            ValidationError = "Please provide at least 2 references.";
            return;
        }
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                ValidationError = "Each reference requires at least a name and email.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

