namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply;

// Mutable view models used by the form steps
public record PersonalInfoModel(string FullName, string Email, string Phone, string Address);
public record WorkEntryModel(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record ReferenceModel(string Name, string Relationship, string Email, string Phone);

@page "/apply"
@namespace sv_f0745fb2dfec4775b343dfb2ac4f212c.Components.Pages.Apply
@rendermode InteractiveServer
@using sv_f0745fb2dfec4775b343dfb2ac4f212c.Models

<PageTitle>Job Application</PageTitle>

<div class="application-form">
    @if (SubmittedApplicationId.HasValue)
    {
        <div class="confirmation">
            <h2>&#10003; Application Submitted!</h2>
            <p>Your application has been received. Your application ID is <strong>#@SubmittedApplicationId</strong>.</p>
            <p>We will review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="@CurrentStep"
                       CompletedUpTo="@CompletedUpTo"
                       OnStepSelected="GoToStep" />

        @switch (CurrentStep)
        {
            case 0:
                <PersonalInfoStep Model="@PersonalInfo"
                                  OnModelChanged="m => PersonalInfo = m"
                                  OnNext="() => AdvanceStep()"
                                  ValidateEmail="ValidateEmailAsync" />
                break;
            case 1:
                <WorkHistoryStep Entries="@WorkEntries"
                                 OnEntriesChanged="e => WorkEntries = e"
                                 OnNext="() => AdvanceStep()"
                                 OnBack="() => GoToStep(CurrentStep - 1)" />
                break;
            case 2:
                <ReferencesStep References="@References"
                                OnReferencesChanged="r => References = r"
                                OnNext="() => AdvanceStep()"
                                OnBack="() => GoToStep(CurrentStep - 1)" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@CoverLetter"
                                 OnCoverLetterChanged="c => CoverLetter = c"
                                 OnNext="() => AdvanceStep()"
                                 OnBack="() => GoToStep(CurrentStep - 1)" />
                break;
            case 4:
                <ReviewStep Personal="@PersonalInfo"
                            WorkEntries="@WorkEntries"
                            References="@References"
                            CoverLetter="@CoverLetter"
                            OnBack="() => GoToStep(CurrentStep - 1)"
                            OnEditStep="GoToStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int CurrentStep = 0;
    private int CompletedUpTo = 0;
    private int? SubmittedApplicationId;

    private PersonalInfoModel PersonalInfo = new(string.Empty, string.Empty, string.Empty, string.Empty);
    private List<WorkEntryModel> WorkEntries = new() { new(string.Empty, string.Empty, DateTime.Today, null, string.Empty) };
    private List<ReferenceModel> References = new()
    {
        new(string.Empty, string.Empty, string.Empty, string.Empty),
        new(string.Empty, string.Empty, string.Empty, string.Empty)
    };
    private string CoverLetter = string.Empty;

    private Task<bool> ValidateEmailAsync(string email)
    {
        return ApplicationService.ValidateEmailAsync(email);
    }

    private void AdvanceStep()
    {
        CurrentStep++;
        if (CurrentStep > CompletedUpTo)
            CompletedUpTo = CurrentStep;
    }

    private void GoToStep(int step)
    {
        if (step >= 0 && step <= 4)
            CurrentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(PersonalInfo.FullName, PersonalInfo.Email, PersonalInfo.Phone, PersonalInfo.Address),
            new WorkHistory(WorkEntries.Select(e => new WorkEntry(e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList()),
            References.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            CoverLetter
        );

        SubmittedApplicationId = await ApplicationService.SubmitApplicationAsync(application);
    }
}

