toolArgs.file_text:
.application-form {
    max-width: 800px;
    margin: 2rem auto;
    padding: 1rem 2rem;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

/* Step Indicator */
.step-indicator {
    margin-bottom: 2rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    cursor: default;
}

.step-item.completed {
    cursor: pointer;
}

.step-marker {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    border: 2px solid #ccc;
    background: #fff;
    color: #999;
    margin-bottom: 0.5rem;
}

.step-item.active .step-marker {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-marker {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-item.dimmed .step-marker {
    border-color: #dee2e6;
    background: #f8f9fa;
    color: #adb5bd;
}

.step-label {
    font-size: 0.8rem;
    text-align: center;
    color: #666;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

.checkmark {
    font-size: 1.1rem;
}

/* Step Content */
.step-content {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 2rem;
}

.step-content h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    color: #333;
}

/* Form Elements */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.25rem;
    font-weight: 500;
    color: #444;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="tel"],
.form-group input[type="date"],
.form-group textarea {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-group textarea {
    resize: vertical;
}

/* Fieldsets */
fieldset.work-entry-form,
fieldset.reference-form {
    border: 1px solid #e9ecef;
    border-radius: 6px;
    padding: 1rem 1.5rem;
    margin-bottom: 1rem;
}

fieldset legend {
    font-weight: 600;
    padding: 0 0.5rem;
    color: #555;
}

/* Buttons */
.step-actions {
    display: flex;
    justify-content: space-between;
    margin-top: 1.5rem;
    padding-top: 1rem;
    border-top: 1px solid #eee;
}

.btn-next, .btn-back, .btn-submit, .btn-add, .btn-remove {
    padding: 0.6rem 1.5rem;
    border: none;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
}

.btn-next {
    background: #0d6efd;
    color: #fff;
    margin-left: auto;
}

.btn-next:hover { background: #0b5ed7; }

.btn-back {
    background: #6c757d;
    color: #fff;
}

.btn-back:hover { background: #5c636a; }

.btn-submit {
    background: #198754;
    color: #fff;
    margin-left: auto;
}

.btn-submit:hover { background: #157347; }

.btn-add {
    background: #f8f9fa;
    color: #0d6efd;
    border: 1px dashed #0d6efd;
    margin-bottom: 1rem;
}

.btn-add:hover { background: #e7f1ff; }

.btn-remove {
    background: #fff;
    color: #dc3545;
    border: 1px solid #dc3545;
    font-size: 0.85rem;
    padding: 0.3rem 0.8rem;
}

.btn-remove:hover { background: #fdf0f1; }

button:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

/* Errors */
.error {
    color: #dc3545;
    font-size: 0.875rem;
    margin-top: 0.25rem;
}

/* Character count */
.char-count {
    text-align: right;
    font-size: 0.85rem;
    color: #6c757d;
    margin-top: 0.25rem;
}

/* Review Step */
.review-section {
    margin-bottom: 1.5rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #eee;
}

.review-section h3 {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 0.75rem;
}

.edit-link {
    font-size: 0.85rem;
    color: #0d6efd;
    cursor: pointer;
    font-weight: normal;
}

.edit-link:hover { text-decoration: underline; }

.review-section dl {
    display: grid;
    grid-template-columns: 100px 1fr;
    gap: 0.25rem 1rem;
    margin: 0;
}

.review-section dt { font-weight: 500; color: #666; }
.review-section dd { margin: 0; }

.review-entry {
    margin-bottom: 0.75rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 4px;
}

.cover-letter-preview {
    white-space: pre-wrap;
    background: #f8f9fa;
    padding: 1rem;
    border-radius: 4px;
}

/* Confirmation */
.confirmation {
    text-align: center;
    padding: 3rem 2rem;
    background: #d1e7dd;
    border: 1px solid #badbcc;
    border-radius: 8px;
}

.confirmation h2 {
    color: #0f5132;
    margin-bottom: 1rem;
}

